'use strict';
/* Historia — the master event dataset. One hand-authored list powers the Grand
 * Timeline, Before/After, Timeline Sort, Guess the Era and the Time Machine.
 *
 * Shape: { id, y (year; negative = BCE), approx?, region, title, blurb, wiki?, fig? }
 *  - era is derived from y via H_ERA_OF_YEAR — never stored.
 *  - blurb: ONE vivid sentence. Storyteller voice, not textbook voice.
 *  - wiki: exact English Wikipedia article title (for summaries/images later).
 *  - fig: related figure id(s) in data/figures.js.
 * Regions: europe · asia · africa · mideast · americas · oceania · global */
window.H_EVENTS = [
  // ===== Ancient World =====
  { id: 'narmer', y: -3100, approx: 1, region: 'africa', title: 'Egypt unified under Narmer', blurb: 'Upper and Lower Egypt merge into history’s first great territorial state — and the pharaohs will run it for 3,000 years.', wiki: 'Narmer' },
  { id: 'giza', y: -2560, approx: 1, region: 'africa', title: 'Great Pyramid completed', blurb: 'Khufu’s tomb at Giza stacks 2.3 million stone blocks and stays the tallest building on Earth for nearly 4,000 years.', wiki: 'Great Pyramid of Giza' },
  { id: 'hammurabi', y: -1754, approx: 1, region: 'mideast', title: 'Code of Hammurabi', blurb: 'A Babylonian king carves 282 laws into a basalt pillar — punishment now depends on what you did, and on who you were.', wiki: 'Code of Hammurabi' },
  { id: 'kadesh', y: -1274, region: 'mideast', title: 'Battle of Kadesh', blurb: 'Ramesses II fights the Hittites to a draw in the biggest chariot battle ever — then both sides sign history’s first surviving peace treaty.', wiki: 'Battle of Kadesh' },
  { id: 'bronzecollapse', y: -1177, approx: 1, region: 'mideast', title: 'Bronze Age collapse', blurb: 'Within a generation, nearly every great Mediterranean civilization burns, starves or vanishes — and we still argue about why.', wiki: 'Late Bronze Age collapse' },
  { id: 'olympics776', y: -776, region: 'europe', title: 'First Olympic Games', blurb: 'A footrace at Olympia begins a festival so sacred that Greek city-states pause their wars to attend.', wiki: 'Ancient Olympic Games' },
  { id: 'rome753', y: -753, approx: 1, region: 'europe', title: 'Legendary founding of Rome', blurb: 'Romulus kills his twin and names a hilltop village after himself — or so Romans told it; the village will own the Mediterranean.', wiki: 'Founding of Rome' },
  { id: 'buddha', y: -528, approx: 1, region: 'asia', title: 'The Buddha’s enlightenment', blurb: 'Under a fig tree at Bodh Gaya, Siddhartha Gautama works out a diagnosis of human suffering that half of Asia will adopt.', wiki: 'Gautama Buddha' },
  { id: 'clisthenes', y: -508, region: 'europe', title: 'Athens invents democracy', blurb: 'Cleisthenes hands power to the demos — flawed and exclusionary, but the first government run by citizen vote.', wiki: 'Athenian democracy' },
  { id: 'marathon', y: -490, region: 'europe', title: 'Battle of Marathon', blurb: 'Outnumbered Athenians charge the Persian line at a run and win — the legend of a messenger’s 26-mile sprint home is born.', wiki: 'Battle of Marathon' },
  { id: 'thermopylae', y: -480, region: 'europe', title: 'Thermopylae & Salamis', blurb: 'Three hundred Spartans die holding a mountain pass; weeks later the Greek fleet shatters Persia’s navy in the straits of Salamis.', wiki: 'Battle of Thermopylae' },
  { id: 'parthenon', y: -447, region: 'europe', title: 'Parthenon rises', blurb: 'Athens spends its empire’s treasury on a temple so mathematically perfect its columns bulge to look straight.', wiki: 'Parthenon' },
  { id: 'socrates', y: -399, region: 'europe', title: 'Trial of Socrates', blurb: 'Athens votes to poison its most annoying citizen for asking too many questions; his student Plato takes notes forever.', wiki: 'Trial of Socrates', fig: ['socrates'] },
  { id: 'alexander', y: -334, region: 'mideast', title: 'Alexander invades Persia', blurb: 'A 21-year-old Macedonian crosses into Asia and doesn’t stop until his empire runs from Greece to India.', wiki: 'Wars of Alexander the Great', fig: ['alexander'] },
  { id: 'qin', y: -221, region: 'asia', title: 'Qin Shi Huang unifies China', blurb: 'The First Emperor standardizes writing, money and axle widths, links the walls, and buries a terracotta army to guard him.', wiki: 'Qin Shi Huang' },
  { id: 'hannibal', y: -218, region: 'europe', title: 'Hannibal crosses the Alps', blurb: 'A Carthaginian general marches war elephants over the mountains into Italy and spends 15 years as Rome’s nightmare.', wiki: 'Hannibal' },
  { id: 'carthage', y: -146, region: 'africa', title: 'Rome destroys Carthage', blurb: 'After a three-year siege Rome burns its great rival flat and enslaves the survivors — the Mediterranean now has one owner.', wiki: 'Third Punic War' },
  { id: 'rubicon', y: -49, region: 'europe', title: 'Caesar crosses the Rubicon', blurb: '“The die is cast” — one legion wades a small stream and the Roman Republic begins to die.', wiki: 'Caesar\'s civil war', fig: ['caesar'] },
  { id: 'ides', y: -44, region: 'europe', title: 'Assassination of Julius Caesar', blurb: 'Twenty-three dagger wounds at a senate meeting; the men who killed him to save the Republic hand it to an emperor instead.', wiki: 'Assassination of Julius Caesar', fig: ['caesar', 'augustus'] },
  { id: 'augustus', y: -27, region: 'europe', title: 'Augustus becomes first emperor', blurb: 'Caesar’s 35-year-old heir keeps the Republic’s titles and takes all of its power — the Roman Empire begins in a paperwork trick.', wiki: 'Augustus', fig: ['augustus'] },
  { id: 'vesuvius', y: 79, region: 'europe', title: 'Vesuvius buries Pompeii', blurb: 'A column of ash 20 miles high entombs two Roman cities so completely that their bread is still in the ovens.', wiki: 'Eruption of Mount Vesuvius in 79 AD' },
  { id: 'teotihuacan', y: 200, approx: 1, region: 'americas', title: 'Teotihuacan at its height', blurb: 'A grid-planned metropolis of 100,000+ rises in Mexico with pyramids to rival Egypt — and we still don’t know who ran it.', wiki: 'Teotihuacan' },
  { id: 'milan313', y: 313, region: 'europe', title: 'Edict of Milan', blurb: 'Constantine legalizes Christianity; within a century the persecuted sect owns the empire that fed it to lions.', wiki: 'Edict of Milan' },
  { id: 'constantinople', y: 330, region: 'europe', title: 'Constantinople founded', blurb: 'Constantine rebuilds a Greek town on the Bosporus as “New Rome” — it will guard the empire’s east for 1,100 more years.', wiki: 'Constantinople' },
  { id: 'romefalls', y: 476, region: 'europe', title: 'Fall of the Western Roman Empire', blurb: 'A teenage emperor is quietly retired by a barbarian general, and nobody bothers to appoint another — antiquity ends with a shrug.', wiki: 'Fall of the Western Roman Empire' },

  // ===== Wave 1 backfill: Ancient World depth (v3) =====
  // --- Mesopotamia & the Levant ---
  { id: 'uruk', y: -3500, approx: 1, region: 'mideast', title: 'Uruk, the first city', blurb: 'In the mudflats of southern Iraq, Uruk swells into the world’s first true city — tens of thousands of strangers learning, for the first time, to live behind one wall.', wiki: 'Uruk' },
  { id: 'cuneiform', y: -3200, approx: 1, region: 'mideast', title: 'Cuneiform invented', blurb: 'Sumerian scribes press reed styluses into wet clay to count barley and beer — and accidentally invent writing, humanity’s first trick for cheating death.', wiki: 'Cuneiform' },
  { id: 'sargonakkad', y: -2334, approx: 1, region: 'mideast', title: 'Sargon builds the first empire', blurb: 'A cupbearer’s son seizes the throne and stitches the warring Sumerian cities into history’s first empire, ruling from a capital archaeologists still cannot find.', wiki: 'Sargon of Akkad', fig: ['sargon'] },
  { id: 'enheduanna', y: -2300, approx: 1, region: 'mideast', title: 'The first author signs her name', blurb: 'A high priestess in Ur signs her hymns to the goddess Inanna with her own name — becoming the first author in all of history we can actually name.', wiki: 'Enheduanna', fig: ['enheduanna'] },
  { id: 'urnammulaw', y: -2100, approx: 1, region: 'mideast', title: 'Code of Ur-Nammu', blurb: 'Three centuries before Hammurabi, the kings of Ur publish the oldest surviving law code — settling wrongs in weighed silver where later rulers would demand an eye.', wiki: 'Code of Ur-Nammu' },
  { id: 'gilgamesh', y: -2100, approx: 1, region: 'mideast', title: 'The Epic of Gilgamesh', blurb: 'A restless king’s hunt for immortality is pressed into clay — a great flood, a snake that steals eternal life, the oldest story humanity still reads.', wiki: 'Epic of Gilgamesh' },
  { id: 'phoenicianalphabet', y: -1050, approx: 1, region: 'mideast', title: 'The Phoenician alphabet', blurb: 'Phoenician traders trim writing down to 22 simple signs — cheap enough for a merchant to master, and the ancestor of nearly every alphabet you know.', wiki: 'Phoenician alphabet' },
  { id: 'solomontemple', y: -957, approx: 1, region: 'mideast', title: 'Solomon’s First Temple', blurb: 'Solomon raises a temple of cedar and gold on a Jerusalem hilltop to house the Ark — the First Temple, and the heart of a faith for four centuries.', wiki: 'Solomon\'s Temple' },
  { id: 'carthagefound', y: -814, approx: 1, region: 'africa', title: 'Carthage founded', blurb: 'Settlers fleeing the Phoenician city of Tyre found Carthage on the African coast — a trading town that will one day make Rome itself tremble.', wiki: 'Carthage' },
  { id: 'ashurbanipallibrary', y: -650, approx: 1, region: 'mideast', title: 'The Library of Nineveh', blurb: 'In Nineveh, an Assyrian king who could actually read hoards thousands of clay tablets — the world’s first great library, baked hard and preserved when the city burned.', wiki: 'Library of Ashurbanipal', fig: ['ashurbanipal'] },
  { id: 'jerusalemexile', y: -587, region: 'mideast', title: 'Fall of Jerusalem & the Exile', blurb: 'Nebuchadnezzar’s army breaks Jerusalem, burns Solomon’s Temple and marches the people of Judah to Babylon — the exile that reshaped an entire religion.', wiki: 'Siege of Jerusalem (587 BC)' },
  { id: 'ishtargate', y: -575, approx: 1, region: 'mideast', title: 'The Ishtar Gate', blurb: 'Nebuchadnezzar sheathes Babylon’s gateway in blue glazed brick studded with golden bulls and dragons — and, legend says, hangs gardens that float in the air.', wiki: 'Ishtar Gate', fig: ['nebuchadnezzar'] },
  // --- Egypt & Nubia/Kush ---
  { id: 'djoser', y: -2670, approx: 1, region: 'africa', title: 'Djoser’s Step Pyramid rises', blurb: 'Egypt’s architect Imhotep stacks six shrinking stone mastabas into the Step Pyramid — the first monumental building in cut stone anywhere on Earth.', wiki: 'Pyramid of Djoser' },
  { id: 'kerma', y: -2450, approx: 1, region: 'africa', title: 'The Kingdom of Kush rises at Kerma', blurb: 'Far up the Nile, Nubia’s first great kingdom grows around the Deffufa, a giant mudbrick temple, becoming Egypt’s rival and its supplier of gold, ebony and ivory.', wiki: 'Kerma culture' },
  { id: 'mentuhotep2', y: -2040, approx: 1, region: 'africa', title: 'Mentuhotep II reunites Egypt', blurb: 'After a century of civil war between rival dynasties, one Theban king reconquers the land and opens the Middle Kingdom, a golden age of literature and towering ambition.', wiki: 'Mentuhotep II' },
  { id: 'hyksos', y: -1650, approx: 1, region: 'africa', title: 'The Hyksos seize the Nile Delta', blurb: 'Foreign rulers from the Levant take northern Egypt, bringing the horse-drawn chariot and the composite bow — weapons Egypt will later turn against them.', wiki: 'Hyksos' },
  { id: 'hatshepsut', y: -1473, approx: 1, region: 'africa', title: 'Hatshepsut crowns herself king', blurb: 'Stepping past her young nephew, Hatshepsut has herself crowned pharaoh — false beard and all — and sends a fleet to the fabled land of Punt for myrrh trees hauled home roots and all.', wiki: 'Hatshepsut', fig: ['hatshepsut'] },
  { id: 'megiddo', y: -1457, approx: 1, region: 'africa', title: 'Thutmose III wins at Megiddo', blurb: 'Gambling on a narrow mountain pass, Thutmose III surprises a Canaanite coalition and wins the first battle in history recorded blow by blow — by his own scribes.', wiki: 'Battle of Megiddo (15th century BC)' },
  { id: 'akhenaten', y: -1348, approx: 1, region: 'africa', title: 'Akhenaten’s one-god revolution', blurb: 'Akhenaten scraps Egypt’s crowded pantheon for a single sun-disk god, raises a brand-new capital from empty desert, and lets its art go strangely, tenderly human.', wiki: 'Akhenaten', fig: ['akhenaten'] },
  { id: 'ramesses2', y: -1279, approx: 1, region: 'africa', title: 'Ramesses the Great takes the throne', blurb: 'Ramesses II begins a 66-year reign of colossal self-portraits, roughly a hundred children, and the world’s first surviving peace treaty.', wiki: 'Ramesses II', fig: ['ramesses2'] },
  { id: 'piye', y: -727, approx: 1, region: 'africa', title: 'Kush conquers Egypt — the Black Pharaohs', blurb: 'The Kushite king Piye sails downriver and takes all of Egypt, founding a Nubian dynasty that rules from the Delta to deep Sudan and buries its kings under steep pyramids.', wiki: 'Piye' },
  { id: 'meroe', y: -300, approx: 1, region: 'africa', title: 'Kush moves its capital to Meroë', blurb: 'The Kushite court shifts south to Meroë and smelts so much iron that slag heaps still ring the city beneath its own field of dozens of slender pyramids.', wiki: 'Meroë' },
  { id: 'alexandrialibrary', y: -283, approx: 1, region: 'africa', title: 'The Library of Alexandria opens', blurb: 'Egypt’s Greek pharaohs set out to collect every scroll on Earth — ships docking in the harbor are searched for books, copied, and the copies handed back.', wiki: 'Library of Alexandria' },
  { id: 'rosetta', y: -196, region: 'africa', title: 'The Rosetta Stone is carved', blurb: 'Priests chisel a routine decree for young Ptolemy V in three scripts onto black granite — a slab that, 2,000 years later, becomes the key that cracks hieroglyphs.', wiki: 'Rosetta Stone' },
  { id: 'amanirenas', y: -24, approx: 1, region: 'africa', title: 'Amanirenas fights Rome', blurb: 'The one-eyed warrior queen Amanirenas leads Kush against Augustus’s Rome, carrying off a bronze head of the emperor to bury under a temple doorway to be trodden forever.', wiki: 'Amanirenas', fig: ['amanirenas'] },
  // --- Persia ---
  { id: 'cyrusempire', y: -550, region: 'mideast', title: 'Cyrus founds the Persian Empire', blurb: 'A minor king in Fars overthrows his own Median grandfather Astyages and, within a decade, forges the largest empire the world has yet seen.', wiki: 'Achaemenid Empire', fig: ['cyrus'] },
  { id: 'cyrusbabylon', y: -539, region: 'mideast', title: 'Cyrus takes Babylon', blurb: 'The great city falls almost without a fight, and Cyrus frees the exiled Jews to go home — a mercy he brags about on a clay barrel we now call the Cyrus Cylinder.', wiki: 'Cyrus Cylinder', fig: ['cyrus'] },
  { id: 'behistun', y: -520, region: 'mideast', title: 'Darius carves the Behistun cliff', blurb: 'To prove he is the rightful king, Darius has his victory chiseled 300 feet up a sheer rock in three languages — the trilingual key that later cracks cuneiform.', wiki: 'Behistun Inscription', fig: ['darius'] },
  { id: 'persepolis', y: -518, region: 'mideast', title: 'Darius begins Persepolis', blurb: 'On a terrace in the mountains, Darius raises a ceremonial capital where subject nations parade gifts up the stairs, linked to the empire by a Royal Road couriers cross in a week.', wiki: 'Persepolis', fig: ['darius'] },
  { id: 'zoroaster', y: -1000, approx: 1, region: 'mideast', title: 'Zoroaster preaches one wise lord', blurb: 'An Iranian prophet reframes the cosmos as a moral war between truth and the lie, under a single creator called Ahura Mazda — one of humanity’s oldest theologies.', wiki: 'Zoroaster', fig: ['zoroaster'] },
  { id: 'persepolisburns', y: -330, region: 'mideast', title: 'Persepolis burns', blurb: 'After a night of feasting, Alexander’s Macedonians torch the jewel of Persia — payback, they say, for the Persians who once burned Athens.', wiki: 'Fall of Persepolis' },
  // --- India ---
  { id: 'indus', y: -2600, approx: 1, region: 'asia', title: 'The cities of the Indus rise', blurb: 'Harappa and Mohenjo-daro lay out grid streets, covered drains and public baths for tens of thousands — yet leave no palaces, no kings, and a script no one can read.', wiki: 'Indus Valley Civilisation' },
  { id: 'vedas', y: -1500, approx: 1, region: 'asia', title: 'The Vedas are composed', blurb: 'Priestly poets set down hymns to fire and dawn that will be memorized syllable-perfect and chanted aloud for a thousand years before anyone dares write them down.', wiki: 'Vedas' },
  { id: 'mahajanapadas', y: -600, approx: 1, region: 'asia', title: 'The sixteen great kingdoms', blurb: 'Across the Ganges plain, tribes harden into sixteen rival states minting the subcontinent’s first coins — and hungry Magadha begins swallowing its neighbors.', wiki: 'Mahajanapadas' },
  { id: 'mahavira', y: -540, approx: 1, region: 'asia', title: 'Mahavira and the Jain path', blurb: 'A prince walks away from his palace to teach absolute non-violence — monks who sweep the ground before each step so as not to crush a single insect.', wiki: 'Mahavira' },
  { id: 'maurya', y: -321, region: 'asia', title: 'Chandragupta forges the Maurya Empire', blurb: 'Guided by the ruthless strategist Chanakya and his handbook the Arthashastra, a young adventurer unites nearly all of India and stares down Alexander’s successors.', wiki: 'Chandragupta Maurya' },
  { id: 'kalinga', y: -261, region: 'asia', title: 'Ashoka turns from war at Kalinga', blurb: 'Sickened by a battlefield of a hundred thousand dead, the conqueror Ashoka lays down the sword for Buddhism and carves promises of mercy onto rocks and pillars across his empire.', wiki: 'Kalinga War', fig: ['ashoka'] },
  { id: 'gupta', y: 320, region: 'asia', title: 'The Gupta golden age begins', blurb: 'Under the Guptas, poets, sculptors and mathematicians flourish — and a small dot for “nothing” quietly matures into the number zero that will remake all arithmetic.', wiki: 'Gupta Empire' },
  { id: 'aryabhata', y: 499, region: 'asia', title: 'Aryabhata spins the Earth', blurb: 'A 23-year-old writes that the heavens only seem to turn because the Earth is rotating, pins pi at 3.1416, and explains eclipses with shadows instead of demons.', wiki: 'Aryabhata', fig: ['aryabhata'] },
  // --- China (Shang → Han) ---
  { id: 'oraclebones', y: -1200, approx: 1, region: 'asia', title: 'Shang diviners invent Chinese writing', blurb: 'Priests at Anyang scorch turtle shells and ox bones until they crack, then carve the gods’ answers beside the cracks — and China’s written language is born.', wiki: 'Oracle bone script' },
  { id: 'zhouconquest', y: -1046, approx: 1, region: 'asia', title: 'Zhou overthrow the Shang', blurb: 'King Wu shatters the Shang army at Muye and justifies it with a radical new idea — that Heaven itself fires cruel rulers and hires better ones.', wiki: 'Mandate of Heaven' },
  { id: 'springautumn', y: -770, region: 'asia', title: 'The Spring and Autumn period begins', blurb: 'With the Zhou kings reduced to figureheads, dozens of dukes start playing for keeps — an age of duels, intrigue and wandering philosophers.', wiki: 'Spring and Autumn period' },
  { id: 'confuciusteach', y: -500, approx: 1, region: 'asia', title: 'Confucius teaches the Way of the gentleman', blurb: 'A failed politician turned wandering teacher tells anyone who will listen that virtue, ritual and plain respect could mend a broken age.', wiki: 'Confucius', fig: ['confucius'] },
  { id: 'daoism', y: -500, approx: 1, region: 'asia', title: 'Laozi and the birth of Daoism', blurb: 'Legend says an old archivist, sick of court life, rode west on an ox and left a border guard five thousand words on going with the flow.', wiki: 'Tao Te Ching', fig: ['laozi'] },
  { id: 'artofwar', y: -500, approx: 1, region: 'asia', title: 'Sun Tzu writes The Art of War', blurb: 'A general boils warfare down to thirteen crisp chapters whose first lesson is that the finest battle is the one you never have to fight.', wiki: 'The Art of War', fig: ['sunzi'] },
  { id: 'warringstates', y: -475, approx: 1, region: 'asia', title: 'The Warring States tear China apart', blurb: 'Seven kingdoms grind each other down with crossbows and conscript armies for two centuries — until only ruthless Qin is left standing.', wiki: 'Warring States period' },
  { id: 'greatwall', y: -214, approx: 1, region: 'asia', title: 'The Great Wall is joined under Qin', blurb: 'The First Emperor sets hundreds of thousands of conscripts to stitch the northern frontier walls into one rammed-earth barrier against the steppe horsemen.', wiki: 'Great Wall of China' },
  { id: 'hanfound', y: -202, region: 'asia', title: 'Liu Bang founds the Han dynasty', blurb: 'A village constable turned rebel outlasts his aristocratic rival, and Liu Bang — born a commoner — starts the 400-year dynasty that still names the Chinese people.', wiki: 'Emperor Gaozu of Han' },
  { id: 'hanconfucian', y: -136, approx: 1, region: 'asia', title: 'Confucianism becomes state doctrine', blurb: 'Emperor Wu adopts Confucianism as the empire’s official creed and quizzes officials on the classics — casting the mold for two thousand years of Chinese government.', wiki: 'Emperor Wu of Han' },
  { id: 'silkroad', y: -130, approx: 1, region: 'asia', title: 'Zhang Qian opens the Silk Road', blurb: 'Sent west to recruit allies against the Xiongnu, the envoy comes home thirteen years late with news of a whole civilized world hungry for Chinese silk.', wiki: 'Zhang Qian' },
  { id: 'shiji', y: -94, approx: 1, region: 'asia', title: 'Sima Qian finishes the Records of the Grand Historian', blurb: 'Choosing castration over suicide so he could keep working, Sima Qian completes the sweeping history he swore to his dying father he would write.', wiki: 'Records of the Grand Historian' },
  { id: 'paper', y: 105, region: 'asia', title: 'Cai Lun perfects paper', blurb: 'A palace eunuch mashes bark, hemp and old rags into cheap smooth sheets and hands the world its writing surface for the next 1,900 years.', wiki: 'Cai Lun' },
  // --- Early Americas ---
  { id: 'caral', y: -2600, approx: 1, region: 'americas', title: 'Caral, the Americas’ oldest city', blurb: 'While Egypt was raising pyramids, a Peruvian valley built its own — six stone platform mounds and sunken plazas, with not one weapon or defensive wall in sight.', wiki: 'Caral' },
  { id: 'povertypoint', y: -1700, approx: 1, region: 'americas', title: 'Poverty Point rises in Louisiana', blurb: 'Long before the pyramids of Mexico, hunter-gatherers in the Mississippi delta hand-carry millions of basketloads of earth into vast concentric ridges.', wiki: 'Poverty Point' },
  { id: 'olmec', y: -1200, approx: 1, region: 'americas', title: 'Olmec civilization rises', blurb: 'Mesoamerica’s first great culture carves multi-ton basalt heads with unmistakable faces, then drags them for miles with no wheels and no draft animals.', wiki: 'Olmecs' },
  { id: 'chavin', y: -900, approx: 1, region: 'americas', title: 'The Chavín cult spreads in the Andes', blurb: 'A mountain temple honeycombed with dark stone galleries draws pilgrims across Peru to a snarling fanged god — the Andes’ first shared religion.', wiki: 'Chavín culture' },
  { id: 'montealban', y: -500, approx: 1, region: 'americas', title: 'Zapotecs build Monte Albán', blurb: 'The Zapotecs level an entire mountaintop by hand to raise a capital in the clouds, carving their slain enemies into eerie stone “Danzante” slabs.', wiki: 'Monte Albán' },
  { id: 'nazca', y: -100, approx: 1, region: 'americas', title: 'The Nazca scratch giant lines', blurb: 'On Peru’s desert floor a people etch a hummingbird, a monkey and a spider so large the shapes only resolve from a sky they could never reach.', wiki: 'Nazca Lines' },
  { id: 'mayalongcount', y: -36, region: 'americas', title: 'The Maya carve their first Long Count date', blurb: 'Maya scribes start tallying days from a mythic zero point in 3114 BCE, a running count so precise it reaches thousands of years past our own century.', wiki: 'Mesoamerican Long Count calendar' },
  // --- Greece & Rome (deep cuts) ---
  { id: 'minoan', y: -1900, approx: 1, region: 'europe', title: 'The palace of Knossos flourishes', blurb: 'Europe’s first great civilization frescoes bull-leaping acrobats onto Crete and plumbs its palace with flush toilets, then fades into the Minotaur myth.', wiki: 'Knossos' },
  { id: 'mycenae', y: -1300, approx: 1, region: 'europe', title: 'Mycenaean warlords rule Greece', blurb: 'Gold-masked kings in citadels of cyclopean stone raid across the Aegean — the world Homer would remember as Agamemnon’s Greeks who sailed for Troy.', wiki: 'Mycenaean Greece' },
  { id: 'iliad', y: -750, approx: 1, region: 'europe', title: 'Homer composes the Iliad and Odyssey', blurb: 'A blind bard — if he existed at all — locks centuries of sung war stories into two epics that Greeks will quote, memorize and live by for a thousand years.', wiki: 'Homer', fig: ['homer'] },
  { id: 'pelopwar', y: -431, region: 'europe', title: 'The Peloponnesian War erupts', blurb: 'Athens and Sparta drag the whole Greek world into a 27-year war that plague, betrayal and a doomed Sicilian expedition turn into Athens’ ruin.', wiki: 'Peloponnesian War' },
  { id: 'archimedes', y: -212, region: 'europe', title: 'Archimedes falls at Syracuse', blurb: 'The sharpest mind of the ancient world is cut down mid-proof by a Roman soldier, reportedly snapping “do not disturb my circles” as the city fell.', wiki: 'Archimedes', fig: ['archimedes'] },
  { id: 'colosseum', y: 80, region: 'europe', title: 'The Colosseum opens', blurb: 'Rome unveils a 50,000-seat stone arena with 100 straight days of games, sun awnings overhead and a floor that could be flooded for mock sea battles.', wiki: 'Colosseum' },

  // ===== Middle Ages =====
  { id: 'hijra', y: 622, region: 'mideast', title: 'The Hijra', blurb: 'Muhammad leads his followers from Mecca to Medina; within a century their faith stretches from Spain to India.', wiki: 'Hijrah' },
  { id: 'tours', y: 732, region: 'europe', title: 'Battle of Tours', blurb: 'Charles “The Hammer” Martel stops the Umayyad advance into France — a hinge point in Europe’s religious map.', wiki: 'Battle of Tours' },
  { id: 'lindisfarne', y: 793, region: 'europe', title: 'Vikings raid Lindisfarne', blurb: 'Longships hit a defenseless island monastery and the Viking Age opens with Europe’s monks writing terrified letters.', wiki: 'Lindisfarne' },
  { id: 'charlemagne', y: 800, region: 'europe', title: 'Charlemagne crowned emperor', blurb: 'On Christmas Day the Pope crowns a Frankish king “Emperor of the Romans” — Europe gets the idea of empire back.', wiki: 'Charlemagne' },
  { id: 'wisdom', y: 830, approx: 1, region: 'mideast', title: 'House of Wisdom flourishes', blurb: 'Baghdad’s scholars translate Greek science, advance algebra (al-jabr) and run the intellectual capital of the planet.', wiki: 'House of Wisdom' },
  { id: 'vinland', y: 1000, approx: 1, region: 'americas', title: 'Leif Erikson reaches Vinland', blurb: 'Norse sailors camp in Newfoundland — Europeans touch the Americas 492 years before Columbus, then leave.', wiki: 'Leif Erikson' },
  { id: 'hastings', y: 1066, region: 'europe', title: 'Battle of Hastings', blurb: 'William of Normandy takes England with an arrow and a cavalry feint; English gets 10,000 French words as a souvenir.', wiki: 'Battle of Hastings' },
  { id: 'crusade1', y: 1095, region: 'mideast', title: 'First Crusade called', blurb: 'Pope Urban II says “God wills it,” and tens of thousands march 2,000 miles to storm Jerusalem.', wiki: 'First Crusade' },
  { id: 'genghis', y: 1206, region: 'asia', title: 'Genghis Khan proclaimed', blurb: 'An orphaned outcast named Temüjin unites the steppe tribes and builds the largest contiguous land empire in history.', wiki: 'Genghis Khan', fig: ['genghis'] },
  { id: 'magnacarta', y: 1215, region: 'europe', title: 'Magna Carta sealed', blurb: 'Rebel barons force King John to admit, in writing, that even the king is under the law — a clause lawyers still quote.', wiki: 'Magna Carta' },
  { id: 'polo', y: 1271, region: 'asia', title: 'Marco Polo departs for China', blurb: 'A Venetian teenager leaves for Kublai Khan’s court; his travel book will keep Europe dreaming of the East for centuries.', wiki: 'Marco Polo' },
  { id: 'mansamusa', y: 1324, region: 'africa', title: 'Mansa Musa’s golden hajj', blurb: 'Mali’s king crosses the Sahara with so much gold he crashes Cairo’s economy — possibly the richest human who ever lived.', wiki: 'Mansa Musa', fig: ['mansamusa'] },
  { id: 'tenochtitlan', y: 1325, approx: 1, region: 'americas', title: 'Tenochtitlan founded', blurb: 'On an island where an eagle ate a snake on a cactus, the Mexica build a canal city that will awe the Spanish.', wiki: 'Tenochtitlan' },
  { id: 'blackdeath', y: 1347, region: 'europe', title: 'Black Death reaches Europe', blurb: 'Plague ships dock in Sicily; within five years a third to half of Europe is dead and the survivors’ world is unrecognizable.', wiki: 'Black Death' },

  // ===== Wave 2 backfill: Middle Ages worldwide (v4) =====
  // Byzantium & the Islamic world · East & SE Asia · medieval Africa · Europe & Vikings · Americas & Pacific
  { id: 'justiniancode', y: 529, region: 'europe', title: 'Justinian’s Code', blurb: 'Justinian’s jurists distill a thousand years of tangled Roman law into one clean code that still underpins legal systems across the world.', wiki: 'Corpus Juris Civilis' },
  { id: 'hagiasophia', y: 537, region: 'europe', title: 'Hagia Sophia rises', blurb: 'Justinian builds a dome so vast it seems hung from heaven; stepping inside, he reportedly gasped, “Solomon, I have outdone you!”', wiki: 'Hagia Sophia' },
  { id: 'justinianplague', y: 541, region: 'europe', title: 'The Plague of Justinian', blurb: 'A pandemic sweeps the empire and kills perhaps a third of its people, shattering Justinian’s dream of putting Rome back together.', wiki: 'Plague of Justinian' },
  { id: 'muhammaddeath', y: 632, region: 'mideast', title: 'Death of Muhammad', blurb: 'The Prophet dies in Medina without clearly naming a successor — the question of who should lead splits Islam into Sunni and Shia to this day.', wiki: 'Death of Muhammad' },
  { id: 'greekfire', y: 672, approx: 1, region: 'europe', title: 'Greek fire unleashed', blurb: 'Byzantine ships spray a clinging liquid flame that burns on water and won’t be doused — a state secret guarded so fiercely its recipe is lost forever.', wiki: 'Greek fire' },
  { id: 'karbala', y: 680, region: 'mideast', title: 'The Martyrdom at Karbala', blurb: 'Muhammad’s grandson Husayn and a tiny band are surrounded and cut down on a desert plain — the martyrdom mourned by Shia Muslims every Ashura.', wiki: 'Battle of Karbala' },
  { id: 'baghdad', y: 762, region: 'mideast', title: 'Baghdad is founded', blurb: 'Caliph al-Mansur lays out a perfectly round city on the Tigris that within a lifetime becomes the largest, richest metropolis on Earth.', wiki: 'Baghdad' },
  { id: 'cordoba', y: 785, region: 'europe', title: 'The Great Mosque of Córdoba', blurb: 'A fugitive prince raises a forest of red-and-white double arches in Al-Andalus, turning a Spanish city into the jewel of the Muslim West.', wiki: 'Mosque–Cathedral of Córdoba' },
  { id: 'cairo', y: 969, region: 'africa', title: 'The Fatimids found Cairo', blurb: 'The Fatimids conquer Egypt and build a brand-new capital they name al-Qahira, “the Victorious” — the city the world now calls Cairo.', wiki: 'Cairo' },
  { id: 'schism', y: 1054, region: 'europe', title: 'The Great Schism', blurb: 'Envoys from Rome and the Patriarch of Constantinople excommunicate each other, cleaving Christianity into Catholic and Orthodox halves that never fully rejoin.', wiki: 'East–West Schism' },
  { id: 'jerusalem1187', y: 1187, region: 'mideast', title: 'Saladin retakes Jerusalem', blurb: 'After annihilating the Crusader army at Hattin, Saladin walks into Jerusalem and — unlike its blood-soaked fall in 1099 — spares the city.', wiki: 'Siege of Jerusalem (1187)', fig: ['saladin'] },
  { id: 'sack1204', y: 1204, region: 'europe', title: 'The Fourth Crusade sacks Constantinople', blurb: 'A crusade sworn to free Jerusalem instead storms Christian Constantinople, looting Europe’s greatest city so thoroughly it never truly recovers.', wiki: 'Sack of Constantinople (1204)' },
  { id: 'baghdad1258', y: 1258, region: 'mideast', title: 'The Mongols sack Baghdad', blurb: 'Hulagu’s army hurls Baghdad’s libraries into the Tigris until the river runs black with ink — and the Islamic Golden Age ends in a single week.', wiki: 'Siege of Baghdad (1258)' },
  { id: 'ibnbattutatravels', y: 1325, region: 'africa', title: 'Ibn Battuta sets out', blurb: 'A 21-year-old leaves Tangier for the hajj and simply keeps going for 29 years, logging some 75,000 miles across the medieval world.', wiki: 'Ibn Battuta', fig: ['ibnbattuta'] },
  { id: 'alhambra', y: 1238, region: 'europe', title: 'The Alhambra begun', blurb: 'The last Muslim kings of Spain start a red hilltop palace of honeycombed ceilings and whispering fountains — a paradise raised as their world shrank.', wiki: 'Alhambra' },
  { id: 'grandcanal', y: 609, region: 'asia', title: 'Grand Canal completed', blurb: 'Emperor Yang drafts millions of laborers to stitch the Yellow and Yangtze rivers into a 1,100-mile waterway — a wonder that outlives the dynasty it bankrupts.', wiki: 'Grand Canal (China)' },
  { id: 'tang', y: 618, region: 'asia', title: 'Tang dynasty founded', blurb: 'A Sui general named Li Yuan seizes the throne and opens three centuries of poetry, silk, and cosmopolitan swagger in Chang’an, the world’s largest city.', wiki: 'Tang dynasty' },
  { id: 'wuzetian', y: 690, region: 'asia', title: 'Wu Zetian takes the throne', blurb: 'A former concubine outmaneuvers an entire court to crown herself emperor — the only woman ever to rule China in her own name.', wiki: 'Wu Zetian', fig: ['wuzetian'] },
  { id: 'anlushan', y: 755, region: 'asia', title: 'An Lushan Rebellion erupts', blurb: 'A trusted frontier general turns his armies on the Tang, and the war that follows may cost tens of millions of lives while poets like Li Bai wander a broken land.', wiki: 'An Lushan Rebellion', fig: ['libai'] },
  { id: 'diamondsutra', y: 868, region: 'asia', title: 'The Diamond Sutra is printed', blurb: 'A Chinese printer inks carved woodblocks to make the world’s oldest dated printed book, closing with a wish that all beings might read it freely.', wiki: 'Diamond Sutra' },
  { id: 'song', y: 960, region: 'asia', title: 'Song dynasty founded', blurb: 'Officers throw a yellow robe over a reluctant general at dawn, founding a dynasty that will invent paper money, gunpowder weapons, and the mariner’s compass.', wiki: 'Song dynasty' },
  { id: 'genji', y: 1008, approx: 1, region: 'asia', title: 'The Tale of Genji written', blurb: 'A lady-in-waiting at the Heian court spins the shining prince’s loves and sorrows into what many call the world’s first novel.', wiki: 'The Tale of Genji', fig: ['murasaki'] },
  { id: 'bisheng', y: 1040, approx: 1, region: 'asia', title: 'Bi Sheng invents movable type', blurb: 'A humble commoner carves individual characters into baked clay, inventing movable-type printing four centuries before Gutenberg was born.', wiki: 'Bi Sheng' },
  { id: 'angkorwat', y: 1150, approx: 1, region: 'asia', title: 'Angkor Wat rises', blurb: 'King Suryavarman II raises the largest religious monument on Earth from the Cambodian forest, its five towers mirroring the peaks where the gods live.', wiki: 'Angkor Wat' },
  { id: 'kamakura', y: 1192, region: 'asia', title: 'Kamakura shogunate begins', blurb: 'Minamoto no Yoritomo takes the title of shogun, and real power in Japan passes from the emperor’s court to the sword of the samurai.', wiki: 'Kamakura shogunate' },
  { id: 'yuan', y: 1271, region: 'asia', title: 'Kublai Khan founds the Yuan', blurb: 'Genghis’s grandson declares himself emperor of China and rules from a new capital at Beijing, the first outsider to hold the whole realm.', wiki: 'Yuan dynasty', fig: ['kublai'] },
  { id: 'kamikaze', y: 1281, region: 'asia', title: 'The divine wind saves Japan', blurb: 'As Kublai Khan’s vast invasion fleet nears Japan a second time, a typhoon smashes it on the rocks — a “kamikaze,” the wind the gods sent.', wiki: 'Mongol invasions of Japan' },
  { id: 'jikji', y: 1377, region: 'asia', title: 'Jikji printed in metal type', blurb: 'Korean monks print a book of Buddhist teachings with movable metal type, making the oldest such volume to survive — decades ahead of Gutenberg.', wiki: 'Jikji' },
  { id: 'aksumchrist', y: 330, approx: 1, region: 'africa', title: 'Aksum turns Christian', blurb: 'King Ezana carves his conversion into stone and stamps the cross onto his coins, making Aksum one of the first kingdoms on earth to embrace Christianity.', wiki: 'Ezana of Axum', fig: ['ezana'] },
  { id: 'aksumstele', y: 350, approx: 1, region: 'africa', title: 'The stelae of Aksum', blurb: 'Aksum’s masons raise granite obelisks up to thirty metres tall over royal tombs — among the largest single stones humans ever tried to stand upright.', wiki: 'Obelisk of Axum' },
  { id: 'transsahara', y: 800, approx: 1, region: 'africa', title: 'Salt for gold', blurb: 'Camel caravans thread the Sahara for weeks, trading slabs of desert salt worth their weight in gold to the forest kingdoms of the south.', wiki: 'Trans-Saharan trade' },
  { id: 'ghanagold', y: 1000, approx: 1, region: 'africa', title: 'Ghana, the land of gold', blurb: 'To Arab traders the empire of Ghana is simply “the land of gold,” its king so rich that al-Bakri records him tethering his horse to a single nugget.', wiki: 'Ghana Empire' },
  { id: 'lalibela', y: 1200, approx: 1, region: 'africa', title: 'Churches carved from rock', blurb: 'King Lalibela’s masons chisel entire churches downward out of solid stone, sinking a cross-shaped chapel into the ground to build a new Jerusalem.', wiki: 'Rock-Hewn Churches, Lalibela', fig: ['lalibela'] },
  { id: 'kirina', y: 1235, approx: 1, region: 'africa', title: 'Sundiata founds Mali', blurb: 'The exiled prince Sundiata Keita, said to have been unable to walk as a boy, returns to crush the sorcerer-king Sumanguru at Kirina and forge the Mali Empire.', wiki: 'Battle of Kirina', fig: ['sundiata'] },
  { id: 'solomonic', y: 1270, region: 'africa', title: 'The Solomonic dynasty', blurb: 'Yekuno Amlak topples the Zagwe and claims descent from King Solomon and the Queen of Sheba, founding a line that would rule Ethiopia for seven centuries.', wiki: 'Yekuno Amlak' },
  { id: 'greatzimbabwe', y: 1300, approx: 1, region: 'africa', title: 'The stone city', blurb: 'On the highveld, masons stack nearly a million granite blocks without a drop of mortar into towering curved walls, crowning a city whose soapstone birds still watch.', wiki: 'Great Zimbabwe' },
  { id: 'kilwa', y: 1300, approx: 1, region: 'africa', title: 'The gold of Kilwa', blurb: 'On a coral island the sultans of Kilwa raise a domed stone mosque and grow fabulously rich taxing the gold that flows out to the Indian Ocean.', wiki: 'Great Mosque of Kilwa' },
  { id: 'djinguereber', y: 1327, region: 'africa', title: 'Timbuktu’s great mosque', blurb: 'Home from his golden pilgrimage, Mansa Musa hires a poet-architect to raise Timbuktu’s vast mud-brick mosque, its walls bristling with wooden scaffolding beams.', wiki: 'Djinguereber Mosque' },
  { id: 'ibnbattutamali', y: 1352, approx: 1, region: 'africa', title: 'Ibn Battuta in Mali', blurb: 'The globe-trotting Moroccan Ibn Battuta reaches Mali and marvels at its justice and safety — while grumbling that the court women go unveiled.', wiki: 'Ibn Battuta', fig: ['ibnbattuta'] },
  { id: 'sankore', y: 1400, approx: 1, region: 'africa', title: 'The scholars of Timbuktu', blurb: 'Timbuktu’s Sankoré mosque swells into a university drawing thousands of scholars, its manuscripts traded for sums that outprice gold.', wiki: 'Sankoré Madrasa' },
  { id: 'askiarise', y: 1493, region: 'africa', title: 'Askia’s Songhai', blurb: 'Askia Muhammad seizes the Songhai throne and rules from the river city of Gao over an empire larger than all of Western Europe.', wiki: 'Songhai Empire', fig: ['askia'] },
  { id: 'clovis', y: 496, approx: 1, region: 'europe', title: 'Clovis unites the Franks', blurb: 'Losing badly at Tolbiac, the pagan king vows to worship his wife’s God if he wins — wins, gets baptized, and hands the Franks their Catholic future.', wiki: 'Clovis I' },
  { id: 'benedict', y: 529, approx: 1, region: 'europe', title: 'The Rule of St Benedict', blurb: 'A hermit fed up with rowdy monks writes a rulebook of prayer, work and “nothing harsh,” and Europe’s libraries survive the next thousand years because of it.', wiki: 'Rule of Saint Benedict' },
  { id: 'kievanrus', y: 862, approx: 1, region: 'europe', title: 'Rurik founds the Rus', blurb: 'Invited to rule warring Slavic towns, the Viking Rurik sails into Novgorod and plants a dynasty that will run Russia for seven hundred years.', wiki: 'Rurik' },
  { id: 'althing', y: 930, region: 'europe', title: 'Iceland’s Althing convenes', blurb: 'Iceland’s free farmers gather on a windswept lava plain to argue and make laws out loud, founding a parliament that still meets today.', wiki: 'Althing' },
  { id: 'cnut', y: 1016, region: 'europe', title: 'Cnut’s North Sea empire', blurb: 'A Danish prince ends up ruling England, Denmark and Norway at once — then sets his throne on the beach to prove even a king can’t command the tide.', wiki: 'Cnut' },
  { id: 'canossa', y: 1077, region: 'europe', title: 'Henry IV at Canossa', blurb: 'Excommunicated and desperate, the Holy Roman Emperor stands three days barefoot in the snow outside a castle gate, begging a pope to forgive him.', wiki: 'Road to Canossa' },
  { id: 'domesday', y: 1086, region: 'europe', title: 'The Domesday Book', blurb: 'William’s clerks fan out across England counting every ox, mill and villager in a survey so final and dreaded that people called it Doomsday.', wiki: 'Domesday Book' },
  { id: 'bologna', y: 1088, region: 'europe', title: 'University of Bologna', blurb: 'Students pool their fees, hire their own professors and fine them for turning up late — inventing the university as we still know it.', wiki: 'University of Bologna' },
  { id: 'elcid', y: 1094, region: 'europe', title: 'El Cid takes Valencia', blurb: 'Exiled by his own king, the mercenary El Cid storms the rich Moorish city of Valencia and rules it as his own private kingdom.', wiki: 'El Cid' },
  { id: 'saintdenis', y: 1140, approx: 1, region: 'europe', title: 'Gothic light at Saint-Denis', blurb: 'Abbot Suger knocks out the heavy walls of his abbey and fills them with glass, and the soaring, luminous thing he builds earns a new name: Gothic.', wiki: 'Basilica of Saint-Denis' },
  { id: 'parliament', y: 1265, region: 'europe', title: 'First English Parliament', blurb: 'Rebel baron Simon de Montfort seats knights and townsmen beside the lords — the first English Parliament, summoned by a man at war with his own king.', wiki: 'Simon de Montfort\'s Parliament' },
  { id: 'aquinas', y: 1274, region: 'europe', title: 'Aquinas lays down his pen', blurb: 'After a lifetime reconciling Aristotle with God across millions of words, Thomas Aquinas has a vision, calls it all “straw,” and never writes again.', wiki: 'Summa Theologica', fig: ['aquinas'] },
  { id: 'crecy', y: 1346, region: 'europe', title: 'Longbows at Crécy', blurb: 'Outnumbered English archers turn French chivalry into a killing field, and the armored knight’s long reign over the battlefield begins to end.', wiki: 'Battle of Crécy' },
  { id: 'canterbury', y: 1387, approx: 1, region: 'europe', title: 'The Canterbury Tales', blurb: 'Geoffrey Chaucer sends a rowdy crowd of pilgrims down the road to Canterbury swapping tales, and gives English its first great poem in its own tongue.', wiki: 'The Canterbury Tales', fig: ['chaucer'] },
  { id: 'tikalheight', y: 700, approx: 1, region: 'americas', title: 'Tikal at its height', blurb: 'Deep in the Petén rainforest, Tikal’s limestone temples pierce the canopy as the city and its rival Calakmul trade wars, kings and captured gods.', wiki: 'Tikal' },
  { id: 'pakaltomb', y: 683, region: 'americas', title: 'Pakal the Great is entombed', blurb: 'They seal the god-king Pakal beneath the Temple of the Inscriptions in a jade mask, his sarcophagus lid carving him falling into the maw of the underworld.', wiki: 'Palenque', fig: ['pakal'] },
  { id: 'dresdencodex', y: 1100, approx: 1, region: 'americas', title: 'The Maya map the sky', blurb: 'In bark-paper books like the surviving Dresden Codex, Maya scribes chart the wanderings of Venus and predict eclipses centuries ahead.', wiki: 'Dresden Codex' },
  { id: 'mayacollapse', y: 900, approx: 1, region: 'americas', title: 'The Classic Maya collapse', blurb: 'Within a few generations the great southern cities fall silent, their plazas surrendered to the jungle for reasons scholars still argue about — drought, war, exhaustion.', wiki: 'Classic Maya collapse' },
  { id: 'tulatoltec', y: 950, approx: 1, region: 'americas', title: 'The Toltecs raise Tula', blurb: 'At Tula the Toltecs stand giant stone warriors atop a pyramid, becoming the fierce ancestors every later Mexican dynasty would claim as their own.', wiki: 'Tula (Mesoamerican site)' },
  { id: 'chichenitza', y: 1000, approx: 1, region: 'americas', title: 'Chichén Itzá rises', blurb: 'A new Maya-Toltec capital blooms in Yucatán, its stepped pyramid El Castillo throwing a serpent of light down its stairs at each equinox.', wiki: 'Chichen Itza' },
  { id: 'mesaverde', y: 1190, approx: 1, region: 'americas', title: 'Cliff Palace at Mesa Verde', blurb: 'The Ancestral Puebloans tuck a village of 150 rooms into a sandstone alcove high above the canyon floor, reachable only by hand-and-toe holds.', wiki: 'Cliff Palace' },
  { id: 'cahokia', y: 1050, approx: 1, region: 'americas', title: 'Cahokia’s great city', blurb: 'Across the river from future St. Louis, Mississippians heap Monks Mound higher than anything else and build the largest city in what’s now the US — unmatched until the 1800s.', wiki: 'Cahokia' },
  { id: 'cuscofounding', y: 1200, approx: 1, region: 'americas', title: 'Manco Cápac founds Cusco', blurb: 'Inca legend says the sun-god’s son Manco Cápac walked from Lake Titicaca until his golden staff sank into the earth, and there raised the city of Cusco.', wiki: 'Manco Cápac' },
  { id: 'chanchan', y: 1300, approx: 1, region: 'americas', title: 'Chan Chan, the adobe capital', blurb: 'The Chimú kingdom rules Peru’s north coast from Chan Chan, the largest mud-brick city on Earth, its walls carved with endless waves and seabirds.', wiki: 'Chan Chan' },
  { id: 'aztectriplealliance', y: 1428, region: 'americas', title: 'The Aztec Triple Alliance', blurb: 'Tenochtitlan, Texcoco and Tlacopan swear a three-city pact under Itzcoatl, and the empire that will dominate Mexico is born.', wiki: 'Aztec Triple Alliance', fig: ['itzcoatl'] },
  { id: 'pachacutiempire', y: 1438, region: 'americas', title: 'Pachacuti forges the Inca Empire', blurb: 'A younger prince turns back an invasion, seizes the throne, and remakes a valley kingdom into Tawantinsuyu, the largest empire the Americas ever saw.', wiki: 'Pachacuti', fig: ['pachacuti'] },
  { id: 'machupicchu', y: 1450, approx: 1, region: 'americas', title: 'Machu Picchu is built', blurb: 'On a knife-edge ridge in the clouds, Pachacuti’s masons fit granite blocks without mortar into a royal estate the Spanish would never find.', wiki: 'Machu Picchu', fig: ['pachacuti'] },
  { id: 'polynesianvoyaging', y: 1000, approx: 1, region: 'oceania', title: 'The great Polynesian expansion', blurb: 'Guided by stars, swells and the flight of birds, navigators in double-hulled canoes leap thousands of miles of open ocean to settle the last empty islands on Earth.', wiki: 'Polynesian navigation' },
  { id: 'tuitonga', y: 1200, approx: 1, region: 'oceania', title: 'The Tuʻi Tonga sea-empire', blurb: 'From the stone-lined harbor of Tonga, the Tuʻi Tonga kings send canoes to collect tribute across a web of islands stretching to Samoa and Fiji.', wiki: 'Tuʻi Tonga Empire' },
  { id: 'hawaiiahupuaa', y: 1250, approx: 1, region: 'oceania', title: 'Hawaiʻi and the ahupuaʻa', blurb: 'Settled voyagers slice each island into ahupuaʻa — pie-shaped strips running from mountain to reef, so every community holds forest, farmland and fishery at once.', wiki: 'Ahupuaʻa' },
  { id: 'maoriaotearoa', y: 1300, approx: 1, region: 'oceania', title: 'Māori settle Aotearoa', blurb: 'The last great migration lands in New Zealand, the coldest, largest islands of Polynesia, where the newcomers become Māori and hunt the giant flightless moa.', wiki: 'Māori people', fig: ['kupe'] },
  { id: 'rapanuimoai', y: 1300, approx: 1, region: 'oceania', title: 'The moai of Rapa Nui', blurb: 'On a speck of Pacific rock, carvers quarry the volcano itself into hundreds of stern-faced giants and walk them miles to stand watch over the living.', wiki: 'Moai' },

  // ===== Renaissance & Discovery =====
  { id: 'gutenberg', y: 1440, approx: 1, region: 'europe', title: 'Gutenberg’s printing press', blurb: 'A Mainz goldsmith bolts together movable type and a wine press — information will never be scarce again.', wiki: 'Johannes Gutenberg' },
  { id: 'const1453', y: 1453, region: 'europe', title: 'Fall of Constantinople', blurb: 'Ottoman cannon crack the walls that held for 1,100 years; refugees carry Greek learning west and feed the Renaissance.', wiki: 'Fall of Constantinople' },
  { id: 'dias', y: 1488, region: 'africa', title: 'Dias rounds the Cape', blurb: 'Bartolomeu Dias survives the storms at Africa’s tip and proves the Atlantic connects to the Indian Ocean.', wiki: 'Bartolomeu Dias' },
  { id: 'columbus', y: 1492, region: 'americas', title: 'Columbus reaches the Americas', blurb: 'Aiming for Asia, three Spanish ships hit the Bahamas — two worlds collide, and neither will ever be the same.', wiki: 'Voyages of Christopher Columbus' },
  { id: 'gama', y: 1498, region: 'asia', title: 'Da Gama reaches India', blurb: 'Vasco da Gama sails into Calicut and opens a sea lane that reroutes the world economy around Africa.', wiki: 'Vasco da Gama' },
  { id: 'monalisa', y: 1503, approx: 1, region: 'europe', title: 'Leonardo begins the Mona Lisa', blurb: 'A Florentine polymath starts a portrait he’ll tinker with for the rest of his life — and never deliver.', wiki: 'Mona Lisa', fig: ['leonardo'] },
  { id: 'sistine', y: 1508, region: 'europe', title: 'Michelangelo paints the Sistine ceiling', blurb: 'A sculptor who insists he’s not a painter spends four years on scaffolding creating painting’s most famous ceiling.', wiki: 'Sistine Chapel ceiling' },
  { id: 'luther', y: 1517, region: 'europe', title: 'Luther’s Ninety-five Theses', blurb: 'A monk’s complaint about the sale of forgiveness goes viral on the new printing presses and splits Western Christianity.', wiki: 'Ninety-five Theses' },
  { id: 'cortes', y: 1521, region: 'americas', title: 'Fall of Tenochtitlan', blurb: 'Cortés, steel, smallpox and thousands of Indigenous allies bring down the Aztec Empire in two brutal years.', wiki: 'Fall of Tenochtitlan' },
  { id: 'magellan', y: 1522, region: 'global', title: 'First circumnavigation completed', blurb: 'Of Magellan’s 270 men, 18 limp home three years later — having proven the planet can be sailed around.', wiki: 'Magellan expedition' },
  { id: 'copernicus', y: 1543, region: 'europe', title: 'Copernicus moves the Earth', blurb: 'On his deathbed he publishes the book that demotes Earth to just another planet circling the Sun.', wiki: 'Nicolaus Copernicus' },
  { id: 'elizabeth', y: 1558, region: 'europe', title: 'Elizabeth I takes the throne', blurb: 'The daughter Henry VIII never wanted begins a 44-year reign that turns a broke island into a rising power.', wiki: 'Elizabeth I', fig: ['elizabeth'] },
  { id: 'armada', y: 1588, region: 'europe', title: 'Spanish Armada defeated', blurb: 'Fireships, gales and English gunnery wreck Spain’s invasion fleet; the sea now has a new boss in training.', wiki: 'Spanish Armada' },
  { id: 'hamlet', y: 1600, approx: 1, region: 'europe', title: 'Shakespeare writes Hamlet', blurb: 'A Stratford actor turns a revenge plot into the deepest character ever put on stage — and mints phrases you used today.', wiki: 'Hamlet', fig: ['shakespeare'] },

  // ===== Early Modern =====
  { id: 'jamestown', y: 1607, region: 'americas', title: 'Jamestown founded', blurb: 'England’s first lasting American colony nearly starves out of existence — then finds its cash crop in tobacco.', wiki: 'Jamestown, Virginia' },
  { id: 'galileo', y: 1610, region: 'europe', title: 'Galileo aims a telescope at the sky', blurb: 'Moons around Jupiter, mountains on the Moon — the heavens turn out to be made of places, not perfection.', wiki: 'Galileo Galilei', fig: ['galileo'] },
  { id: 'mayflower', y: 1620, region: 'americas', title: 'Mayflower lands at Plymouth', blurb: 'Separatists blown off course sign a compact to govern themselves before stepping ashore — self-rule in miniature.', wiki: 'Mayflower' },
  { id: 'galileotrial', y: 1633, region: 'europe', title: 'Galileo tried by the Inquisition', blurb: 'Forced to kneel and deny the Earth moves, the old man reputedly mutters “and yet it moves.”', wiki: 'Galileo affair', fig: ['galileo'] },
  { id: 'qing', y: 1644, region: 'asia', title: 'Qing dynasty takes Beijing', blurb: 'Manchu horsemen ride through a rebel-opened gate and begin China’s last imperial dynasty.', wiki: 'Qing dynasty' },
  { id: 'westphalia', y: 1648, region: 'europe', title: 'Peace of Westphalia', blurb: 'Europe ends 30 years of religious slaughter by inventing the modern rulebook: sovereign states, fixed borders.', wiki: 'Peace of Westphalia' },
  { id: 'principia', y: 1687, region: 'europe', title: 'Newton publishes the Principia', blurb: 'Three laws and one gravity explain apples, tides, cannonballs and planets in a single system — physics is born.', wiki: 'Philosophiæ Naturalis Principia Mathematica', fig: ['newton'] },
  { id: 'kite', y: 1752, region: 'americas', title: 'Franklin’s kite experiment', blurb: 'A Philadelphia printer flies a kite into a storm and bottles proof that lightning is electricity.', wiki: 'Kite experiment', fig: ['franklin'] },

  // ===== Age of Revolutions =====
  { id: 'stampact', y: 1765, region: 'americas', title: 'Stamp Act ignites the colonies', blurb: 'Britain taxes paper itself; colonists answer with a slogan that sticks — no taxation without representation.', wiki: 'Stamp Act 1765' },
  { id: 'teaparty', y: 1773, region: 'americas', title: 'Boston Tea Party', blurb: 'Colonists in disguise dump 342 chests of tea into the harbor — an act of political theater Britain can’t ignore.', wiki: 'Boston Tea Party' },
  { id: 'congress1774', y: 1774, region: 'americas', title: 'First Continental Congress in Philadelphia', blurb: 'Twelve colonies send delegates to Carpenters’ Hall and discover, arguing face to face, that they might be one country.', wiki: 'First Continental Congress' },
  { id: 'lexington', y: 1775, region: 'americas', title: 'Lexington and Concord', blurb: 'A shot nobody claims firing — “heard round the world” — turns a protest movement into a war.', wiki: 'Battles of Lexington and Concord' },
  { id: 'declaration', y: 1776, region: 'americas', title: 'Declaration of Independence', blurb: 'In a brick hall in Philadelphia, thirteen colonies declare that all men are created equal — a promise still being collected on.', wiki: 'United States Declaration of Independence', fig: ['franklin', 'washington'] },
  { id: 'yorktown', y: 1781, region: 'americas', title: 'Victory at Yorktown', blurb: 'Washington’s army and the French fleet trap Cornwallis; a British band reportedly plays “The World Turned Upside Down.”', wiki: 'Siege of Yorktown', fig: ['washington'] },
  { id: 'constitution', y: 1787, region: 'americas', title: 'Constitutional Convention in Philadelphia', blurb: 'Fifty-five delegates, one sweltering summer behind locked doors — out comes the oldest written national constitution still running.', wiki: 'Constitutional Convention (United States)', fig: ['franklin', 'washington'] },
  { id: 'bastille', y: 1789, region: 'europe', title: 'Storming of the Bastille', blurb: 'A Paris crowd takes the king’s fortress-prison and finds just seven prisoners — but the symbol brings down a thousand years of monarchy.', wiki: 'Storming of the Bastille' },
  { id: 'haiti', y: 1791, region: 'americas', title: 'Haitian Revolution begins', blurb: 'The enslaved people of Saint-Domingue rise and, against three empires, win the only successful slave revolution in history.', wiki: 'Haitian Revolution' },
  { id: 'yellowfever', y: 1793, region: 'americas', title: 'Yellow fever ravages Philadelphia', blurb: 'The U.S. capital loses a tenth of its people in three months; the federal government literally flees the city.', wiki: '1793 Philadelphia yellow fever epidemic' },
  { id: 'louisiana', y: 1803, region: 'americas', title: 'Louisiana Purchase', blurb: 'Napoleon, needing war money, sells Jefferson 828,000 square miles for about four cents an acre.', wiki: 'Louisiana Purchase' },
  { id: 'napoleon', y: 1804, region: 'europe', title: 'Napoleon crowns himself emperor', blurb: 'He takes the crown from the Pope’s hands and puts it on his own head — ambition with excellent stage direction.', wiki: 'Coronation of Napoleon', fig: ['napoleon'] },
  { id: 'waterloo', y: 1815, region: 'europe', title: 'Battle of Waterloo', blurb: 'One rainy Belgian Sunday ends Napoleon for good; “meeting your Waterloo” enters every language in Europe.', wiki: 'Battle of Waterloo', fig: ['napoleon'] },
  { id: 'bolivar', y: 1819, region: 'americas', title: 'Bolívar wins at Boyacá', blurb: 'After a march over frozen Andes passes, Simón Bolívar shatters Spanish power in New Granada — South America’s liberation accelerates.', wiki: 'Battle of Boyacá' },
  { id: 'rocket', y: 1830, region: 'europe', title: 'First intercity railway opens', blurb: 'The Liverpool–Manchester line, led by Stephenson’s Rocket, makes distance itself negotiable.', wiki: 'Liverpool and Manchester Railway' },
  { id: 'abolition', y: 1833, region: 'europe', title: 'Britain abolishes slavery', blurb: 'Parliament outlaws slavery across most of the empire — abolitionists prove a moral campaign can beat an economy.', wiki: 'Slavery Abolition Act 1833' },
  { id: 'trailoftears', y: 1838, region: 'americas', title: 'Trail of Tears', blurb: 'The U.S. Army marches the Cherokee Nation west at gunpoint; thousands die on the road their descendants still mourn.', wiki: 'Trail of Tears' },
  { id: 'senecafalls', y: 1848, region: 'americas', title: 'Seneca Falls Convention', blurb: 'The first women’s rights convention rewrites Jefferson: “all men and women are created equal.”', wiki: 'Seneca Falls Convention' },
  { id: 'rev1848', y: 1848, region: 'europe', title: 'Revolutions sweep Europe', blurb: 'From Paris to Vienna, fifty uprisings in one year — most fail fast, but the old order never fully recovers.', wiki: 'Revolutions of 1848' },

  // ===== Industrial Age =====
  { id: 'darwin', y: 1859, region: 'europe', title: 'Darwin publishes On the Origin of Species', blurb: 'Twenty years of barnacles and finches distilled into one idea — descent with modification — that reorganizes biology forever.', wiki: 'On the Origin of Species', fig: ['darwin'] },
  { id: 'civilwar', y: 1861, region: 'americas', title: 'American Civil War begins', blurb: 'Shots at Fort Sumter start a four-year war over slavery that will kill more Americans than every other U.S. war combined.', wiki: 'American Civil War', fig: ['lincoln'] },
  { id: 'gettysburg', y: 1863, region: 'americas', title: 'Gettysburg & the Address', blurb: 'Three July days break the Confederate tide; four months later Lincoln redefines the war in 272 words.', wiki: 'Gettysburg Address', fig: ['lincoln'] },
  { id: 'appomattox', y: 1865, region: 'americas', title: 'Civil War ends; Lincoln assassinated', blurb: 'Lee surrenders on Palm Sunday; five days later a bullet at Ford’s Theatre turns victory into national grief.', wiki: 'Assassination of Abraham Lincoln', fig: ['lincoln'] },
  { id: 'transcontinental', y: 1869, region: 'americas', title: 'Transcontinental railroad completed', blurb: 'A golden spike at Promontory Summit shrinks a six-month wagon ordeal to a one-week train ride.', wiki: 'First transcontinental railroad' },
  { id: 'suez', y: 1869, region: 'africa', title: 'Suez Canal opens', blurb: 'Egypt’s new ditch between two seas cuts the Europe–Asia voyage by 4,000 miles and rewires global trade.', wiki: 'Suez Canal' },
  { id: 'bell1876', y: 1876, region: 'americas', title: 'The telephone debuts in Philadelphia', blurb: 'At the Centennial Exhibition celebrating America’s 100th birthday, Alexander Graham Bell makes a wire talk.', wiki: 'Centennial Exposition' },
  { id: 'edison', y: 1879, region: 'americas', title: 'Edison’s practical light bulb', blurb: 'After thousands of tested filaments, a carbonized thread burns for hours — night becomes optional.', wiki: 'Thomas Edison', fig: ['edison'] },
  { id: 'benz', y: 1886, region: 'europe', title: 'Benz patents the automobile', blurb: 'A three-wheeled carriage with a gas engine putters through Mannheim; his wife Bertha will invent the road trip.', wiki: 'Benz Patent-Motorwagen' },
  { id: 'nzvote', y: 1893, region: 'oceania', title: 'New Zealand: women win the vote', blurb: 'First country on Earth where women vote in national elections — the suffrage dam starts to crack.', wiki: 'Women\'s suffrage in New Zealand' },
  { id: 'olympics1896', y: 1896, region: 'europe', title: 'First modern Olympics', blurb: 'Athens revives the ancient games after 1,500 years; 14 nations, zero women — both numbers will change.', wiki: '1896 Summer Olympics' },
  { id: 'wright', y: 1903, region: 'americas', title: 'Wright brothers fly', blurb: 'Twelve seconds and 120 feet over Kitty Hawk sand — shorter than a 747’s wingspan, and it changes the species.', wiki: 'Wright Flyer' },
  { id: 'einstein1905', y: 1905, region: 'europe', title: 'Einstein’s miracle year', blurb: 'A patent clerk publishes four papers in one year — light quanta, atoms, E=mc² and special relativity.', wiki: 'Annus mirabilis papers', fig: ['einstein'] },
  { id: 'titanic', y: 1912, region: 'global', title: 'Titanic sinks', blurb: 'The unsinkable ship meets the iceberg on its first crossing; 1,500 die, and the age of hubris gets its metaphor.', wiki: 'Sinking of the Titanic' },
  { id: 'fordline', y: 1913, region: 'americas', title: 'Ford’s moving assembly line', blurb: 'Building a car drops from 12 hours to 93 minutes — mass production makes the machine age affordable.', wiki: 'Assembly line' },

  // ===== World Wars =====
  { id: 'sarajevo', y: 1914, region: 'europe', title: 'Assassination in Sarajevo', blurb: 'A 19-year-old kills an archduke whose driver took a wrong turn; a month later all of Europe is at war.', wiki: 'Assassination of Archduke Franz Ferdinand' },
  { id: 'somme', y: 1916, region: 'europe', title: 'Battle of the Somme', blurb: 'On day one, Britain loses 57,000 men for a few yards of mud — the machine gun has made courage obsolete.', wiki: 'Battle of the Somme' },
  { id: 'russianrev', y: 1917, region: 'europe', title: 'Russian Revolution', blurb: 'Bread riots topple the tsar in February; by October, Lenin’s Bolsheviks seize the world’s largest country.', wiki: 'Russian Revolution' },
  { id: 'armistice', y: 1918, region: 'europe', title: 'Armistice ends the Great War', blurb: 'At the 11th hour of the 11th day of the 11th month the guns stop — 20 million dead, and the peace will curdle.', wiki: 'Armistice of 11 November 1918' },
  { id: 'flu1918', y: 1918, region: 'global', title: 'Influenza pandemic', blurb: 'A flu strain kills more people in two years than the war did in four — perhaps 50 million worldwide.', wiki: 'Spanish flu' },
  { id: 'suffrage1920', y: 1920, region: 'americas', title: '19th Amendment ratified', blurb: 'After a 72-year campaign, American women win the vote — by one Tennessee legislator’s changed mind.', wiki: 'Nineteenth Amendment to the United States Constitution' },
  { id: 'crash1929', y: 1929, region: 'global', title: 'Wall Street Crash', blurb: 'The market loses a decade of gains in days; the Depression that follows puts a quarter of America out of work.', wiki: 'Wall Street Crash of 1929' },
  { id: 'hitler1933', y: 1933, region: 'europe', title: 'Hitler becomes chancellor', blurb: 'Handed power by politicians sure they can control him, he needs 53 days to end German democracy.', wiki: 'Adolf Hitler\'s rise to power' },
  { id: 'newdeal', y: 1933, region: 'americas', title: 'The New Deal begins', blurb: 'FDR’s first hundred days throw the federal government at the Depression — banks, dams, jobs, and radio “fireside chats.”', wiki: 'New Deal' },
  { id: 'owens', y: 1936, region: 'europe', title: 'Jesse Owens wins four golds in Berlin', blurb: 'A Black American sprinter demolishes the Nazis’ master-race showcase in front of Hitler himself.', wiki: 'Jesse Owens' },
  { id: 'poland1939', y: 1939, region: 'europe', title: 'Germany invades Poland', blurb: 'Blitzkrieg — lightning war — hits Poland from three sides; two days later, Britain and France declare war.', wiki: 'Invasion of Poland' },
  { id: 'britain1940', y: 1940, region: 'europe', title: 'Battle of Britain', blurb: 'A few thousand fighter pilots deny the Luftwaffe the sky; “never was so much owed by so many to so few.”', wiki: 'Battle of Britain', fig: ['churchill'] },
  { id: 'pearlharbor', y: 1941, region: 'americas', title: 'Attack on Pearl Harbor', blurb: 'Japan sinks the Pacific Fleet’s battleships in 90 minutes and wakes “a sleeping giant” — America is all in.', wiki: 'Attack on Pearl Harbor' },
  { id: 'stalingrad', y: 1942, region: 'europe', title: 'Battle of Stalingrad begins', blurb: 'Five months of fighting room to room in a frozen city break the German army’s spine in the east.', wiki: 'Battle of Stalingrad' },
  { id: 'dday', y: 1944, region: 'europe', title: 'D-Day', blurb: 'The largest seaborne invasion ever puts 156,000 men on five Norman beaches in one gray dawn.', wiki: 'Normandy landings' },
  { id: 'hiroshima', y: 1945, region: 'asia', title: 'Hiroshima and Nagasaki', blurb: 'Two bombs, two cities, one week — the war ends and the atomic age begins with a question that never goes away.', wiki: 'Atomic bombings of Hiroshima and Nagasaki' },
  { id: 'un1945', y: 1945, region: 'global', title: 'United Nations founded', blurb: 'Fifty-one nations sign a charter in San Francisco betting that talking beats another world war.', wiki: 'United Nations' },

  // ===== Cold War & Space Age =====
  { id: 'partition', y: 1947, region: 'asia', title: 'Indian independence & Partition', blurb: 'The Raj ends at midnight; freedom arrives twinned with a partition that uproots 14 million people.', wiki: 'Partition of India', fig: ['gandhi'] },
  { id: 'airlift', y: 1948, region: 'europe', title: 'Berlin Airlift', blurb: 'Stalin blockades West Berlin, so the Allies fly in everything — a plane landing every 45 seconds for 11 months.', wiki: 'Berlin Blockade' },
  { id: 'prc1949', y: 1949, region: 'asia', title: 'People’s Republic of China founded', blurb: 'Mao proclaims the PRC from Tiananmen gate; a quarter of humanity changes systems overnight.', wiki: 'Proclamation of the People\'s Republic of China' },
  { id: 'dna1953', y: 1953, region: 'europe', title: 'DNA’s double helix revealed', blurb: 'Watson and Crick — standing on Rosalind Franklin’s X-ray — find life’s twisted-ladder blueprint.', wiki: 'DNA' },
  { id: 'everest', y: 1953, region: 'asia', title: 'Everest summited', blurb: 'Edmund Hillary and Tenzing Norgay stand on the roof of the world with 15 minutes to spare on their oxygen.', wiki: '1953 British Mount Everest expedition' },
  { id: 'rosaparks', y: 1955, region: 'americas', title: 'Rosa Parks keeps her seat', blurb: 'One refusal on a Montgomery bus launches a 381-day boycott and lifts a 26-year-old preacher named King into history.', wiki: 'Montgomery bus boycott', fig: ['rosaparks', 'mlk'] },
  { id: 'sputnik', y: 1957, region: 'global', title: 'Sputnik orbits Earth', blurb: 'A beeping Soviet sphere the size of a beach ball panics America into inventing NASA — the Space Race is on.', wiki: 'Sputnik 1' },
  { id: 'gagarin', y: 1961, region: 'global', title: 'Gagarin: first human in space', blurb: '108 minutes, one orbit, one enormous smile — a farm boy turned cosmonaut becomes the first human off the planet.', wiki: 'Yuri Gagarin' },
  { id: 'berlinwall', y: 1961, region: 'europe', title: 'Berlin Wall goes up', blurb: 'Overnight, barbed wire splits a city; families wave to each other across it for 28 years.', wiki: 'Berlin Wall' },
  { id: 'cuba1962', y: 1962, region: 'americas', title: 'Cuban Missile Crisis', blurb: 'Thirteen October days of nuclear chicken — the closest the world has ever come to ending itself.', wiki: 'Cuban Missile Crisis' },
  { id: 'march1963', y: 1963, region: 'americas', title: 'March on Washington', blurb: 'A quarter-million people hear King depart from his script — “I have a dream” — at Lincoln’s feet.', wiki: 'March on Washington for Jobs and Freedom', fig: ['mlk'] },
  { id: 'civilrights1964', y: 1964, region: 'americas', title: 'Civil Rights Act signed', blurb: 'Jim Crow’s legal spine snaps: discrimination in jobs and public places is outlawed nationwide.', wiki: 'Civil Rights Act of 1964', fig: ['mlk'] },
  { id: 'apollo11', y: 1969, region: 'global', title: 'Apollo 11 lands on the Moon', blurb: 'With 30 seconds of fuel in the tank, two humans park on another world while 600 million watch.', wiki: 'Apollo 11', fig: ['armstrong'] },
  { id: 'saigon1975', y: 1975, region: 'asia', title: 'Fall of Saigon', blurb: 'Helicopters lift the last Americans off a rooftop; the Vietnam War ends the way it was fought — chaotically.', wiki: 'Fall of Saigon' },
  { id: 'chernobyl', y: 1986, region: 'europe', title: 'Chernobyl disaster', blurb: 'A 2 a.m. safety test gone wrong scatters fallout across Europe and cracks Soviet credibility for good.', wiki: 'Chernobyl disaster' },
  { id: 'wallfalls', y: 1989, region: 'europe', title: 'Berlin Wall falls', blurb: 'A botched press conference opens the gates by accident; Berliners dance on the wall with hammers by midnight.', wiki: 'Fall of the Berlin Wall' },
  { id: 'mandela1990', y: 1990, region: 'africa', title: 'Mandela walks free', blurb: 'After 27 years in prison he emerges preaching reconciliation, not revenge — and four years later he’s president.', wiki: 'Nelson Mandela', fig: ['mandela'] },
  { id: 'ussrend', y: 1991, region: 'europe', title: 'Soviet Union dissolves', blurb: 'The hammer-and-sickle comes down over the Kremlin on Christmas night; the Cold War ends with a flag change.', wiki: 'Dissolution of the Soviet Union' },

  // ===== Information Age =====
  { id: 'web', y: 1991, region: 'global', title: 'World Wide Web goes public', blurb: 'A CERN physicist posts his hypertext project to the internet and declines to patent it — you’re using it right now.', wiki: 'World Wide Web' },
  { id: 'mandela1994', y: 1994, region: 'africa', title: 'Mandela elected president', blurb: 'South Africans of every race queue for miles in the country’s first free election; apartheid is voted out of existence.', wiki: '1994 South African general election', fig: ['mandela'] },
  { id: 'deepblue', y: 1997, region: 'global', title: 'Deep Blue defeats Kasparov', blurb: 'A chess computer beats the world champion in a match — machines claim their first famous piece of human intellect.', wiki: 'Deep Blue versus Garry Kasparov' },
  { id: 'sept11', y: 2001, region: 'americas', title: 'September 11 attacks', blurb: 'Four hijacked planes kill nearly 3,000 people and bend the trajectory of the new century in a single morning.', wiki: 'September 11 attacks' },
  { id: 'wikipedia', y: 2001, region: 'global', title: 'Wikipedia launches', blurb: 'An encyclopedia anyone can edit sounds like a terrible idea — and becomes the largest reference work in human history.', wiki: 'History of Wikipedia' },
  { id: 'genome', y: 2003, region: 'global', title: 'Human genome sequenced', blurb: 'Thirteen years and 3 billion letters later, humanity reads its own source code cover to cover.', wiki: 'Human Genome Project' },
  { id: 'iphone', y: 2007, region: 'global', title: 'The iPhone', blurb: 'A phone, an iPod and an internet communicator walk on stage — and put a supercomputer in half of humanity’s pockets.', wiki: 'IPhone (1st generation)' },
  { id: 'crisis2008', y: 2008, region: 'global', title: 'Global financial crisis', blurb: 'A housing bubble wired into everything detonates; Lehman falls and the world economy stalls for years.', wiki: '2008 financial crisis' },
  { id: 'higgs', y: 2012, region: 'europe', title: 'Higgs boson found', blurb: 'A 17-mile ring under Geneva confirms the particle predicted 48 years earlier — the mass-giver exists.', wiki: 'Higgs boson' },
  { id: 'covid', y: 2020, region: 'global', title: 'COVID-19 pandemic', blurb: 'A novel coronavirus empties the world’s cities in weeks — and vaccines arrive in under a year, a scientific land-speed record.', wiki: 'COVID-19 pandemic' },
  { id: 'jwst', y: 2022, region: 'global', title: 'Webb telescope opens its eye', blurb: 'A million miles out, an origami mirror colder than Pluto starts photographing the universe’s baby pictures.', wiki: 'James Webb Space Telescope' },
];
